```class Solution {
public:
    int countLargestGroup(int n) {
        int result = 0;
        int sum = 0;
        for (int i = 1; i <= n; i++) {
            sum += (i % 10);
            result += (sum >= i);
            sum /= 10;
        }
        return result;
    }
};```

